AC_UID = "ac7-cf1-no-suppress-regex-wildcard-grants"
AC_TYPE = "hook"

_REPO = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", ".."))
_HOOKS_DIR = os.path.join(_REPO, "hooks")
_ALLOW_HOOK = os.path.join(_REPO, "hooks", "userprompt-consent-allowlist.sh")
_PYTHON = os.path.join(_REPO, "venv", "bin", "python")
if not os.path.isfile(_PYTHON):
    _PYTHON = "python3"


def test_AC7():
    """
    GIVEN: user issues /allow .* or /allow re:.*python.* (regex/wildcard sentinel; is_regex=true → op: *)
    WHEN:  pretool-bash-safety.sh processes the sentinel
    THEN:  EITHER (a) no sentinel file exists for the regex grant (preferred: is_regex=true → skip sentinel write in userprompt-consent-allowlist.sh), OR (b) sentinel has legacy_fallback_allowed: true and is exempted from SENTINEL_EXISTS_FOR_TASK=1; AND legacy check_and_consume_allowlist IS consulted
    """
    session_id = "ac7-test-sid"
    task_id = session_id
    sentinel_file = f"/tmp/claude-grants/{task_id}.json"
    legacy_flag = f"/tmp/claude-bash-allowlist-{session_id}.json"

    # Simulate /allow .* via userprompt-consent-allowlist.sh
    allow_payload = json.dumps({
        "prompt": "/allow .*",
        "session_id": session_id,
    })
    env = os.environ.copy()
    env["CLAUDE_TASK_ID"] = task_id
    env["CLAUDE_PYTHON_FALLBACK"] = "python3"  # venv symlinks broken in ramdisk env
    env.pop("CLAUDE_SESSION_ID", None)

    try:
        # Run userprompt-consent-allowlist.sh (simulates user typing /allow .*)
        allow_proc = subprocess.run(
            ["bash", _ALLOW_HOOK],
            input=allow_payload,
            capture_output=True,
            text=True,
            env=env,
            cwd=_HOOKS_DIR,
        )
        assert allow_proc.returncode == 0, (
            f"userprompt-consent-allowlist.sh failed: {allow_proc.stderr}"
        )

        # S1 fix: for is_regex=true, no sentinel should be written
        # Preferred outcome (a): sentinel file does NOT exist
        if os.path.exists(sentinel_file):
            # If sentinel exists, it must have legacy_fallback_allowed: true (option b)
            with open(sentinel_file) as f:
                sentinel_data = json.load(f)
            assert sentinel_data.get("legacy_fallback_allowed") is True, (
                f"Sentinel written for regex grant but lacks legacy_fallback_allowed:true. "
                f"CF-1 will suppress legacy path, breaking /allow .* for IS_SUBAGENT=1.\n"
                f"sentinel: {sentinel_data}"
            )
        # else: no sentinel written (S1 skip path — preferred)

        # Now verify legacy path IS consulted when the command matches the regex grant.
        # Write the legacy allowlist flag (as userprompt-consent-allowlist.sh step 3 did).
        # If sentinel was NOT written (S1), then no SENTINEL_EXISTS_NO_MATCH fires,
        # and legacy path proceeds normally.
        # Verify by running pretool-bash-safety.sh and checking it does NOT emit the CF-1 suppression message.
        cmd = "/tmp/xlsx-venv/bin/python /root/orchestra/docs/dev/find_red_cells.py > /root/orchestra/docs/research/case-3"
        payload = json.dumps({
            "tool_name": "Bash",
            "tool_input": {"command": cmd},
            "agent_id": "ag1",
            "session_id": session_id,
        })
        # Ensure legacy flag exists (simulating that userprompt-consent-allowlist.sh wrote it)
        with open(legacy_flag, "w") as f:
            json.dump({"pattern": ".*", "is_regex": True}, f)

        proc = subprocess.run(
            ["bash", os.path.join(_HOOKS_DIR, "pretool-bash-safety.sh")],
            input=payload,
            capture_output=True,
            text=True,
            env=env,
            cwd=_HOOKS_DIR,
        )
        # CF-1 must NOT suppress the legacy path for regex grants (no SENTINEL_EXISTS_NO_MATCH)
        assert "legacy /allow path suppressed" not in proc.stderr, (
            f"CF-1 suppressed legacy path for regex grant — S1 fix not working\n"
            f"stderr: {proc.stderr}"
        )
    finally:
        for f in [sentinel_file, legacy_flag]:
            if os.path.exists(f):
                os.unlink(f)
